import React, { useState, useCallback, useRef, useEffect } from "react";
import Scoreboard from "./Scoreboard";
import PowerBar from "./PowerBar";
import Pitch, { IDLE, BOWLING, BATTING, RESULT_SHOW } from "./Pitch";

const MAX_BALLS = 12;
const MAX_WICKETS = 2;

const PROBABILITIES = {
  aggressive: [
    { type: "W", prob: 0.40 },
    { type: "0", prob: 0.10 },
    { type: "1", prob: 0.10 },
    { type: "2", prob: 0.10 },
    { type: "3", prob: 0.05 },
    { type: "4", prob: 0.10 },
    { type: "6", prob: 0.15 },
  ],
  defensive: [
    { type: "W", prob: 0.20 },
    { type: "0", prob: 0.30 },
    { type: "1", prob: 0.20 },
    { type: "2", prob: 0.10 },
    { type: "3", prob: 0.05 },
    { type: "4", prob: 0.10 },
    { type: "6", prob: 0.05 },
  ],
};

const COMMENTARY = {
  W: [
    "Clean bowled! The stumps are shattered!",
    "Top edge and the fielder takes a simple catch!",
    "Beaten by the delivery — that's out!",
    "The batsman misjudged the line completely!",
  ],
  "6": [
    "Massive six! That's gone all the way!",
    "Cleared the ropes with ease — what a strike!",
    "Into the stands! The crowd goes wild!",
  ],
  "4": [
    "Cracked through the covers — four runs!",
    "Drives hard and it races to the boundary!",
    "Brilliant placement, no fielder near it!",
  ],
  "3": ["Great running between the wickets — three!", "Hard work pays off — three runs!"],
  "2": ["Pushed into the gap, they run two.", "Decent placement, two runs."],
  "1": ["Tapped away for a single.", "Just a nudge — one run."],
  "0": ["Beaten outside off — dot ball.", "Defended solidly, no run.", "Played and missed!"],
};

function getCommentary(type) {
  const options = COMMENTARY[type] || ["Good delivery."];
  return options[Math.floor(Math.random() * options.length)];
}

function getResult(position, style) {
  const probs = PROBABILITIES[style];
  let sum = 0;
  for (const seg of probs) {
    sum += seg.prob;
    if (position <= sum) return seg.type;
  }
  return probs[probs.length - 1].type;
}

// Phases: idle → bowling → batting → result → idle (next ball)
const PHASE = { IDLE: "idle", BOWLING: "bowling", BATTING: "batting", RESULT: "result" };

function Game() {
  const [runs, setRuns] = useState(0);
  const [wickets, setWickets] = useState(0);
  const [balls, setBalls] = useState(0);
  const [style, setStyle] = useState("aggressive");
  const [result, setResult] = useState(null);
  const [commentary, setCommentary] = useState("");
  const [phase, setPhase] = useState(PHASE.IDLE);
  const [gameOver, setGameOver] = useState(false);
  const [ballHistory, setBallHistory] = useState([]);

  const phaseRef = useRef(PHASE.IDLE);
  const runsRef = useRef(0);
  const wicketsRef = useRef(0);
  const ballsRef = useRef(0);

  // Sync refs
  useEffect(() => { phaseRef.current = phase; }, [phase]);
  useEffect(() => { runsRef.current = runs; }, [runs]);
  useEffect(() => { wicketsRef.current = wickets; }, [wickets]);
  useEffect(() => { ballsRef.current = balls; }, [balls]);

  const startBall = useCallback(() => {
    if (gameOver) return;
    setPhase(PHASE.BOWLING);
  }, [gameOver]);

  // When bowling animation is done (Pitch calls this via phase timing)
  // We handle timing in Game itself
  useEffect(() => {
    if (phase === PHASE.BOWLING) {
      // Bowling animation runs ~1.1s in Pitch, then we wait for user click (PowerBar)
      // Actually: bowling phase is just the "ball rolling" — user clicks during this!
      // We allow the user to click during BOWLING phase.
    }
  }, [phase]);

  const handleShot = useCallback((position) => {
    if (phase !== PHASE.BOWLING) return;

    const res = getResult(position, style);
    const comm = getCommentary(res);

    setResult(res);
    setCommentary(comm);
    setPhase(PHASE.BATTING);

    // Update scores
    const newBalls = ballsRef.current + 1;
    let newWickets = wicketsRef.current;
    let newRuns = runsRef.current;

    if (res === "W") {
      newWickets = wicketsRef.current + 1;
      setWickets(newWickets);
    } else {
      newRuns = runsRef.current + parseInt(res);
      setRuns(newRuns);
    }
    setBalls(newBalls);

    // Add to ball history
    setBallHistory(prev => [...prev, res]);

    // After batting animation, show result briefly then reset
    setTimeout(() => {
      setPhase(PHASE.RESULT);
      // Check game over
      if (newBalls >= MAX_BALLS || newWickets >= MAX_WICKETS) {
        setTimeout(() => setGameOver(true), 900);
      } else {
        setTimeout(() => {
          setPhase(PHASE.IDLE);
          setResult(null);
          setCommentary("");
        }, 1400);
      }
    }, 600);
  }, [phase, style]);

  // Map our phase to Pitch's expected animPhase
  const pitchPhase = (() => {
    if (phase === PHASE.BOWLING) return BOWLING;
    if (phase === PHASE.BATTING || phase === PHASE.RESULT) return BATTING;
    return IDLE;
  })();

  const isDisabled = phase !== PHASE.BOWLING || gameOver;

  const restart = () => {
    setRuns(0);
    setWickets(0);
    setBalls(0);
    setResult(null);
    setCommentary("");
    setPhase(PHASE.IDLE);
    setGameOver(false);
    setBallHistory([]);
    runsRef.current = 0;
    wicketsRef.current = 0;
    ballsRef.current = 0;
  };

  const overStr = `${Math.floor(balls / 6)}.${balls % 6}`;

  return (
    <div className="game-container">
      {/* Header */}
      <div className="game-header">
        <div className="game-title">🏏 2D Cricket</div>
        <div className="header-subtitle">
          {style === "aggressive" ? "⚡ Aggressive" : "🛡️ Defensive"} Mode
        </div>
      </div>

      {/* Scoreboard */}
      <Scoreboard
        runs={runs}
        wickets={wickets}
        balls={balls}
        maxBalls={MAX_BALLS}
        maxWickets={MAX_WICKETS}
      />

      {/* Ball-by-ball history */}
      <div className="ball-history">
        {ballHistory.map((b, i) => (
          <span
            key={i}
            className={`ball-dot ${
              b === "W" ? "dot-wicket" :
              b === "6" ? "dot-six" :
              b === "4" ? "dot-four" :
              b === "0" ? "dot-zero" : "dot-runs"
            }`}
          >
            {b === "W" ? "W" : b}
          </span>
        ))}
        {Array.from({ length: MAX_BALLS - ballHistory.length }).map((_, i) => (
          <span key={`empty-${i}`} className="ball-dot dot-empty">·</span>
        ))}
      </div>

      {/* Pitch */}
      <Pitch result={result} animPhase={pitchPhase} commentary={commentary} />

      {/* Style selection + Play */}
      {!gameOver && (
        <div className="controls">
          <div className="style-row">
            <button
              className={`style-btn ${style === "aggressive" ? "active" : ""}`}
              onClick={() => { if (phase === PHASE.IDLE) setStyle("aggressive"); }}
              disabled={phase !== PHASE.IDLE}
            >
              ⚡ Aggressive
              <span className="style-hint">High risk · High reward</span>
            </button>
            <button
              className={`style-btn ${style === "defensive" ? "active" : ""}`}
              onClick={() => { if (phase === PHASE.IDLE) setStyle("defensive"); }}
              disabled={phase !== PHASE.IDLE}
            >
              🛡️ Defensive
              <span className="style-hint">Safe play · Lower reward</span>
            </button>
          </div>

          {phase === PHASE.IDLE && (
            <button className="bowl-btn" onClick={startBall}>
              🎳 Bowl Next Ball
            </button>
          )}
        </div>
      )}

      {/* Power Bar */}
      {!gameOver && (
        <div className="powerbar-section">
          <h3 className="powerbar-title">
            Power Bar — <span className="style-tag">{style.toUpperCase()}</span>
          </h3>
          <PowerBar
            styleType={style}
            onShot={handleShot}
            disabled={isDisabled}
          />
        </div>
      )}

      {/* Game Over Screen */}
      {gameOver && (
        <div className="gameover-overlay">
          <div className="gameover-card">
            <div className="gameover-title">
              {wickets >= MAX_WICKETS ? "💔 All Out!" : "🏁 Innings Complete!"}
            </div>
            <div className="gameover-score">
              <span className="go-runs">{runs}</span>
              <span className="go-label">runs</span>
              <span className="go-sep">/</span>
              <span className="go-wickets">{wickets}</span>
              <span className="go-label">wickets</span>
            </div>
            <div className="go-detail">
              in {overStr} overs
            </div>
            <div className="go-rating">
              {runs >= 80 ? "🔥 Exceptional innings!" :
               runs >= 50 ? "👏 Great batting!" :
               runs >= 30 ? "✅ Decent effort." :
               "📉 Poor show today."}
            </div>
            <div className="ball-history gameover-history">
              {ballHistory.map((b, i) => (
                <span
                  key={i}
                  className={`ball-dot ${
                    b === "W" ? "dot-wicket" :
                    b === "6" ? "dot-six" :
                    b === "4" ? "dot-four" :
                    b === "0" ? "dot-zero" : "dot-runs"
                  }`}
                >
                  {b === "W" ? "W" : b}
                </span>
              ))}
            </div>
            <button className="restart-btn" onClick={restart}>
              🔄 Play Again
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default Game;
